  ('bookkeeper-moex-01048', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '甲公司之債權人乙公司，經甲公司允許僅能查閱該公司財務報表，為深入瞭解甲公司財務狀況，須查核 該公司會計帳簿報表及憑證，則乙公司在何種情況下才能檢查甲公司之會計帳簿報表及憑證？ 向甲公司轄區國稅局提出申請 向甲公司商業會計事務主管機關提出申請 向法務部行政執行署提出申請 聲請法院選派檢查員，檢查甲公司之會計帳簿報表及憑證', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
